import { defineConfig } from 'vite'
import react from '@vitejs/plugin-react'

export default defineConfig({
  plugins: [react()],
  server: {
    host: '0.0.0.0',
    port: 5000,
    allowedHosts: true,
    proxy: {
      '/upload': 'http://localhost:8000',
      '/summary': 'http://localhost:8000',
      '/ips': 'http://localhost:8000',
      '/protocols': 'http://localhost:8000',
      '/flows': 'http://localhost:8000',
      '/logs': 'http://localhost:8000',
    },
  },
})

import axios from "axios";

const api = axios.create({
  baseURL: "",
});

export default api;

arguments.code:
await configureWorkflow({
  name: "Start application",
  command: "cd frontend && npm run dev",
  waitForPort: 5000,
  outputType: "webview",
  autoStart: true
});
console.log("Frontend workflow configured");

await configureWorkflow({
  name: "Backend API",
  command: "cd backend && python -m uvicorn app:app --host localhost --port 8000",
  waitForPort: 8000,
  outputType: "console",
  autoStart: true
});
console.log("Backend workflow configured");

await configureWorkflow({
  name: "Backend API",
  command: "python -m uvicorn backend.app:app --host localhost --port 8000",
  waitForPort: 8000,
  outputType: "console",
  autoStart: true
});
console.log("Backend workflow reconfigured");

const status = await getWorkflowStatus({ name: "Backend API" });
console.log("State:", status.state);
console.log("Output:", status.output);
console.log("Ports:", status.openPorts);

const result = await deployConfig({
    deploymentTarget: "autoscale",
    run: ["bash", "-c", "python -m uvicorn backend.app:app --host localhost --port 8000 & cd frontend && npm run build && npx serve -s dist -l 5000"],
    build: ["bash", "-c", "cd frontend && npm install && npm run build && pip install -r backend/requirements.txt"]
});
console.log(JSON.stringify(result));

