   109→  const aggregated = Array.from(grouped.values()).map((event) => {
   110→    const thickness = Math.min(12, Math.max(1, Math.log10(Math.max(event.bytes, 10))));
   111→    return {
   112→      ...event,
   113→      thickness,
   114→      color: PROTOCOL_COLORS[event.protocol] || "#38bdf8",
   115→      sourceIndex: 0,
   116→      destIndex: null,
   117→    };
   118→  });
   119→
   120→  const remoteOrder = [...new Set(aggregated.map((item) => item.remote))];
   121→  const lanes = [targetIP, ...remoteOrder];
   122→
   123→  const chartData = aggregated.map((item) => {
   124→    const destIndex = Math.max(1, lanes.indexOf(item.remote));
   125→    return [
   126→      0,
   127→      item.time,
   128→      destIndex,
   129→      item.time,
   130→      item.thickness,
   131→      item.protocol,
   132→      item.bytes,
   133→      item.duration,
   134→      item.source,
   135→      item.destination,
   136→      item.remote,
   137→      item.color,
   138→    ];
   139→  });
   140→
   141→  self.postMessage({
   142→    type: "flows",
   143→    payload: {
   144→      lanes,
   145→      chartData,
   146→    },
   147→  });
   148→};
